// Typical POSIX shared memory workflow:
#include <sys/mman.h>
#include <fcntl.h>
#include <unistd.h>

int fd = shm_open("/my_shm", O_CREAT | O_RDWR, 0666);
ftruncate(fd, SIZE);
void *ptr = mmap(NULL, SIZE, PROT_READ | PROT_WRITE,
                 MAP_SHARED, fd, 0);
close(fd);  // fd no longer needed after mmap

// ... use ptr to read/write shared data ...

munmap(ptr, SIZE);
shm_unlink("/my_shm");  // remove when done

// Named semaphore operations:
#include <semaphore.h>
#include <fcntl.h>

sem_t *sem = sem_open("/my_sem", O_CREAT, 0666, 1);
// ... use sem_post(sem) and sem_wait(sem) ...
sem_close(sem);      // close when process no longer needs it
sem_unlink("/my_sem"); // remove from system when done
